// DApp Smart Contract Interaction Module
// Uses ethers.js for building and sending transactions securely

const { ethers } = require('ethers');

// ============================================
// Configuration & Constants
// ============================================

const SUPPORTED_NETWORKS = {
  1: { name: 'Ethereum Mainnet', rpcUrl: 'https://mainnet.infura.io/v3/' },
  5: { name: 'Goerli Testnet', rpcUrl: 'https://goerli.infura.io/v3/' },
  11155111: { name: 'Sepolia Testnet', rpcUrl: 'https://sepolia.infura.io/v3/' },
  137: { name: 'Polygon Mainnet', rpcUrl: 'https://polygon-rpc.com' },
};

const MAX_GAS_LIMIT = 3000000n;
const MIN_GAS_LIMIT = 21000n;
const MAX_VALUE_ETH = 100;
const TX_TIMEOUT_MS = 120000;
const MAX_RETRIES = 3;

// ============================================
// Input Validation Module
// ============================================

class InputValidator {
  static sanitizeString(input) {
    if (typeof input !== 'string') {
      throw new ValidationError('Input must be a string');
    }
    return input.trim().replace(/[<>\"'&]/g, '');
  }

  static validateAddress(address) {
    const sanitized = this.sanitizeString(address);
    if (!ethers.isAddress(sanitized)) {
      throw new ValidationError(`Invalid Ethereum address: ${sanitized}`);
    }
    return ethers.getAddress(sanitized); // Returns checksummed address
  }

  static validateABI(abi) {
    if (!Array.isArray(abi)) {
      throw new ValidationError('ABI must be an array');
    }
    if (abi.length === 0) {
      throw new ValidationError('ABI cannot be empty');
    }
    // Validate each ABI entry has required fields
    for (const entry of abi) {
      if (typeof entry !== 'object' || entry === null) {
        throw new ValidationError('Each ABI entry must be an object');
      }
      if (entry.type && !['function', 'event', 'constructor', 'fallback', 'receive', 'error'].includes(entry.type)) {
        throw new ValidationError(`Invalid ABI entry type: ${entry.type}`);
      }
    }
    return abi;
  }

  static validateFunctionName(name) {
    const sanitized = this.sanitizeString(name);
    if (!/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(sanitized)) {
      throw new ValidationError(`Invalid function name: ${sanitized}`);
    }
    return sanitized;
  }

  static validateValue(value) {
    if (value === undefined || value === null || value === '') {
      return '0';
    }
    const sanitized = this.sanitizeString(String(value));
    const numValue = parseFloat(sanitized);
    if (isNaN(numValue) || numValue < 0) {
      throw new ValidationError('Value must be a non-negative number');
    }
    if (numValue > MAX_VALUE_ETH) {
      throw new ValidationError(`Value exceeds maximum allowed (${MAX_VALUE_ETH} ETH)`);
    }
    return sanitized;
  }

  static validateGasLimit(gasLimit) {
    if (gasLimit === undefined || gasLimit === null) {
      return null; // Will be estimated
    }
    const limit = BigInt(gasLimit);
    if (limit < MIN_GAS_LIMIT || limit > MAX_GAS_LIMIT) {
      throw new ValidationError(`Gas limit must be between ${MIN_GAS_LIMIT} and ${MAX_GAS_LIMIT}`);
    }
    return limit;
  }

  static validateFunctionArgs(args, abiInputs) {
    if (!Array.isArray(args)) {
      throw new ValidationError('Function arguments must be an array');
    }
    if (abiInputs && args.length !== abiInputs.length) {
      throw new ValidationError(
        `Expected ${abiInputs.length} arguments but received ${args.length}`
      );
    }
    return args.map((arg, index) => {
      if (typeof arg === 'string') {
        // Check if it's an address type
        if (abiInputs && abiInputs[index] && abiInputs[index].type === 'address') {
          return this.validateAddress(arg);
        }
        return this.sanitizeString(arg);
      }
      return arg;
    });
  }

  static validateNetworkId(networkId) {
    const id = Number(networkId);
    if (!Number.isInteger(id) || id <= 0) {
      throw new ValidationError('Invalid network ID');
    }
    return id;
  }
}

// ============================================
// Custom Error Classes
