class ValidationError extends Error {
  constructor(message) {
    super(message);
    this.name = 'ValidationError';
  }
}

class TransactionError extends Error {
  constructor(message, txHash = null) {
    super(message);
    this.name = 'TransactionError';
    this.txHash = txHash;
  }
}

class ConnectionError extends Error {
  constructor(message) {
    super(message);
    this.name = 'ConnectionError';
  }
}

// ============================================
// Secure Event Logger
// ============================================

class SecureLogger {
  static log(level, message, data = {}) {
    const sanitizedData = { ...data };
    // Remove sensitive fields from logs
    const sensitiveFields = ['privateKey', 'mnemonic', 'seed', 'password', 'secret'];
    for (const field of sensitiveFields) {
      if (sanitizedData[field]) {
        sanitizedData[field] = '[REDACTED]';
      }
    }
    const logEntry = {
      timestamp: new Date().toISOString(),
      level,
      message,
      data: sanitizedData,
    };
    console[level === 'error' ? 'error' : 'log'](JSON.stringify(logEntry));
  }

  static info(message, data) { this.log('info', message, data); }
  static warn(message, data) { this.log('warn', message, data); }
  static error(message, data) { this.log('error', message, data); }
}

// ============================================
// Rate Limiter
// ============================================

class RateLimiter {
  constructor(maxRequests = 10, windowMs = 60000) {
    this.maxRequests = maxRequests;
    this.windowMs = windowMs;
    this.requests = [];
  }

  checkLimit() {
    const now = Date.now();
    this.requests = this.requests.filter(ts => now - ts < this.windowMs);
    if (this.requests.length >= this.maxRequests) {
      throw new ValidationError('Rate limit exceeded. Please wait before making more requests.');
    }
    this.requests.push(now);
    return true;
  }
}

// ============================================
// Nonce Manager
// ============================================

class NonceManager {
  constructor() {
    this.nonces = new Map();
    this.locks = new Map();
  }

  async acquireLock(address) {
    while (this.locks.get(address)) {
      await new Promise(resolve => setTimeout(resolve, 50));
    }
    this.locks.set(address, true);
  }

  releaseLock(address) {
    this.locks.set(address, false);
  }

  async getNextNonce(provider, address) {
    await this.acquireLock(address);
    try {
      const onChainNonce = await provider.getTransactionCount(address, 'pending');
      const localNonce = this.nonces.get(address);
      const nextNonce = localNonce !== undefined ? Math.max(localNonce, onChainNonce) : onChainNonce;
      this.nonces.set(address, nextNonce + 1);
      return nextNonce;
    } finally {
      this.releaseLock(address);
    }
  }

  resetNonce(address) {
    this.nonces.delete(address);
  }
}

// ============================================
// Transaction Builder
// ============================================

class TransactionBuilder {
  constructor(contract, signer, provider) {
    this.contract = contract;
    this.signer = signer;
    this.provider = provider;
  }

  async buildCallTransaction(functionName, args, overrides = {}) {
    const validatedFnName = InputValidator.validateFunctionName(functionName);

    // Verify function exists in contract
    const fragment = this.contract.interface.getFunction(validatedFnName);
    if (!fragment) {
      throw new ValidationError(`Function '${validatedFnName}' not found in contract ABI`);
    }

    // Validate arguments against ABI
    const validatedArgs = InputValidator.validateFunctionArgs(args, fragment.inputs);

    // Build transaction overrides
    const txOverrides = {};

    if (overrides.value) {
      const validatedValue = InputValidator.validateValue(overrides.value);
      if (!fragment.payable && parseFloat(validatedValue) > 0) {
        throw new ValidationError(`Function '${validatedFnName}' is not payable`);
      }
      txOverrides.value = ethers.parseEther(validatedValue);
    }

    if (overrides.gasLimit) {
      txOverrides.gasLimit = InputValidator.validateGasLimit(overrides.gasLimit);
    }

    return { functionName: validatedFnName, args: validatedArgs, overrides: txOverrides };
  }

  async estimateGas(functionName, args, overrides = {}) {
    try {
      const estimated = await this.contract[functionName].estimateGas(...args, overrides);
      // Add 20% buffer for safety
      const buffered = (estimated * 120n) / 100n;
      return buffered > MAX_GAS_LIMIT ? MAX_GAS_LIMIT : buffered;
    } catch (error) {
      SecureLogger.warn('Gas estimation failed, using default', { functionName, error: error.message });
      return 200000n;
    }
  }
}

// ============================================
// Main DApp Contract Interaction Class
// ============================================

class DAppContractInteractor {
  constructor(config = {}) {
    this.provider = null;
    this.signer = null;
    this.contracts = new Map();
    this.rateLimiter = new RateLimiter(
      config.maxRequestsPerMinute || 10,
      config.rateLimitWindowMs || 60000
    );
    this.nonceManager = new NonceManager();
    this.infuraApiKey = config.infuraApiKey || '';
    this.connected = false;
    this.currentNetwork = null;
  }

  // ---- Connection Methods ----

  async connectWithBrowserWallet() {
    if (typeof window === 'undefined' || !window.ethereum) {
      throw new ConnectionError('No browser wallet detected. Please install MetaMask or a compatible wallet.');
    }

    try {
      // Request account access
      await window.ethereum.request({ method: 'eth_requestAccounts' });

      this.provider = new ethers.BrowserProvider(window.ethereum);
      this.signer = await this.provider.getSigner();

      const network = await this.provider.getNetwork();
      this.currentNetwork = Number(network.chainId);
      this.connected = true;

      SecureLogger.info('Connected with browser wallet', {
        network: this.currentNetwork,
        address: await this.signer.getAddress(),
      });

      // Listen for account and network changes
      this._setupWalletListeners();

      return {
        address: await this.signer.getAddress(),
        network: this.currentNetwork,
      };
    } catch (error) {
      throw new ConnectionError(`Failed to connect wallet: ${error.message}`);
    }
  }

  async connectWithProvider(networkId, infuraApiKey) {
    const validatedNetworkId = InputValidator.validateNetworkId(networkId);
    const networkConfig = SUPPORTED_NETWORKS[validatedNetworkId];

    if (!networkConfig) {
      throw new ValidationError(`Unsupported network ID: ${validatedNetworkId}`);
    }

    const apiKey = infuraApiKey || this.infuraApiKey;
    const rpcUrl = networkConfig.rpcUrl.includes('infura')
      ? `${networkConfig.rpcUrl}${apiKey}`
      : networkConfig.rpcUrl;

    try {
      this.provider = new ethers.JsonRpcProvider(rpcUrl);
      await this.provider.getNetwork(); // Verify connection
      this.currentNetwork = validatedNetworkId;
      this.connected = true;

      SecureLogger.info('Connected to provider', { network: networkConfig.name });

      return { network: validatedNetworkId, name: networkConfig.name };
    } catch (error) {
      throw new ConnectionError(`Failed to connect to ${networkConfig.name}: ${error.message}`);
    }
  }

  _setupWalletListeners() {
    if (typeof window !== 'undefined' && window.ethereum) {
      window.ethereum.on('accountsChanged', (accounts) => {
        SecureLogger.info('Account changed', { newAccount: accounts[0] });
        this.nonceManager = new NonceManager();
        // Emit event for UI update
        if (this.onAccountChanged) this.onAccountChanged(accounts[0]);
      });

      window.ethereum.on('chainChanged', (chainId) => {
        SecureLogger.info('Network changed', { newChainId: chainId });
        this.currentNetwork = Number(chainId);
        this.contracts.clear();
        this.nonceManager = new NonceManager();
        if (this.onNetworkChanged) this.onNetworkChanged(Number(chainId));
      });
    }
  }

  // ---- Contract Management ----

  loadContract(contractAddress, abi, label = null) {
    this._ensureConnected();

    const validatedAddress = InputValidator.validateAddress(contractAddress);
    const validatedABI = InputValidator.validateABI(abi);

    const contract = this.signer
      ? new ethers.Contract(validatedAddress, validatedABI, this.signer)
      : new ethers.Contract(validatedAddress, validatedABI, this.provider);

    const key = label || validatedAddress;
    this.contracts.set(key, {
      contract,
      address: validatedAddress,
      abi: validatedABI,
      builder: new TransactionBuilder(contract, this.signer, this.provider),
    });

    SecureLogger.info('Contract loaded', { address: validatedAddress, label: key });

    return key;
  }

  getContract(labelOrAddress) {
    const entry = this.contracts.get(labelOrAddress);
    if (!entry) {
      throw new ValidationError(`Contract not found: ${labelOrAddress}`);
    }
    return entry;
  }

  // ---- Read Operations (View/Pure functions) ----

  async readContract(contractKey, functionName, args = []) {
    this._ensureConnected();
    this.rateLimiter.checkLimit();

    const { contract, builder } = this.getContract(contractKey);
    const { functionName: validatedFn, args: validatedArgs } = await builder.buildCallTransaction(
      functionName,
      args
    );

    // Verify it's a view/pure function
    const fragment = contract.interface.getFunction(validatedFn);
    if (fragment.stateMutability !== 'view' && fragment.stateMutability !== 'pure') {
      throw new ValidationError(
        `Function '${validatedFn}' is not a view/pure function. Use sendTransaction instead.`
      );
    }

    try {
      const result = await contract[validatedFn](...validatedArgs);
      SecureLogger.info('Contract read successful', { function: validatedFn });
      return this._formatResult(result, fragment);
    } catch (error) {
      SecureLogger.error('Contract read failed', { function: validatedFn, error: error.message });
      throw new TransactionError(`Read failed: ${error.message}`);
    }
  }

  // ---- Write Operations (State-changing functions) ----

  async sendTransaction(contractKey, functionName, args = [], overrides = {}) {
    this._ensureConnected();
    this._ensureSigner();
    this.rateLimiter.checkLimit();

    const { contract, builder } = this.getContract(contractKey);
    const {
      functionName: validatedFn,
      args: validatedArgs,
      overrides: validatedOverrides,
    } = await builder.buildCallTransaction(functionName, args, overrides);

    // Estimate gas if not provided
    if (!validatedOverrides.gasLimit) {
      validatedOverrides.gasLimit = await builder.estimateGas(
        validatedFn,
        validatedArgs,
        validatedOverrides
      );
    }

    // Get managed nonce
    const signerAddress = await this.signer.getAddress();
    validatedOverrides.nonce = await this.nonceManager.getNextNonce(this.provider, signerAddress);

    SecureLogger.info('Sending transaction', {
      function: validatedFn,
      to: contract.target,
      gasLimit: validatedOverrides.gasLimit.toString(),
      nonce: validatedOverrides.nonce,
    });

    try {
      // Simulate the transaction first (dry run)
      await this._simulateTransaction(contract, validatedFn, validatedArgs, validatedOverrides);

      // Send the actual transaction
      const tx = await contract[validatedFn](...validatedArgs, validatedOverrides);

      SecureLogger.info('Transaction sent', { txHash: tx.hash });

      return {
        hash: tx.hash,
        wait: () => this._waitForConfirmation(tx),
        transaction: tx,
      };
    } catch (error) {
      // Reset nonce on failure
      this.nonceManager.resetNonce(signerAddress);
      SecureLogger.error('Transaction failed', {
        function: validatedFn,
        error: error.message,
      });
      throw new TransactionError(`Transaction failed: ${error.message}`);
    }
  }

  async _simulateTransaction(contract, functionName, args, overrides) {
    try {
      const simulationOverrides = { ...overrides };
      delete simulationOverrides.nonce; // Remove nonce for static call
      await contract[functionName].staticCall(...args, simulationOverrides);
    } catch (error) {
      const reason = this._decodeRevertReason(error);
      throw new TransactionError(`Transaction would revert: ${reason}`);
    }
  }

  async _waitForConfirmation(tx, confirmations = 1) {
    const timeoutPromise = new Promise((_, reject) =>
      setTimeout(() => reject(new TransactionError('Transaction confirmation timeout', tx.hash)), TX_TIMEOUT_MS)
    );

    const receiptPromise = tx.wait(confirmations);

    try {
      const receipt = await Promise.race([receiptPromise, timeoutPromise]);

      if (receipt.status === 0) {
        throw new TransactionError('Transaction reverted on-chain', tx.hash);
      }

      SecureLogger.info('Transaction confirmed', {
        txHash: receipt.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
      });

      return {
        hash: receipt.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
        status: receipt.status,
        logs: receipt.logs,
      };
    } catch (error) {
      if (error instanceof TransactionError) throw error;
      throw new TransactionError(`Confirmation failed: ${error.message}`, tx.hash);
    }
  }

  // ---- Batch Operations ----

  async batchRead(contractKey, calls) {
    this._ensureConnected();

    if (!Array.isArray(calls) || calls.length === 0) {
      throw new ValidationError('Calls must be a non-empty array');
    }

    if (calls.length > 50) {
      throw new ValidationError('Maximum 50 batch calls allowed');
    }

    const results = [];
    for (const call of calls) {
      try {
        const result = await this.readContract(contractKey, call.functionName, call.args || []);
        results.push({ success: true, result });
      } catch (error) {
        results.push({ success: false, error: error.message });
      }
    }

    return results;
  }

  // ---- Event Listening ----

  subscribeToEvents(contractKey, eventName, callback, filters = {}) {
    this._ensureConnected();

    const { contract } = this.getContract(contractKey);
    const sanitizedEventName = InputValidator.sanitizeString(eventName);

    // Verify event exists in ABI
    const eventFragment = contract.interface.getEvent(sanitizedEventName);
    if (!eventFragment) {
      throw new ValidationError(`Event '${sanitizedEventName}' not found in contract ABI`);
    }

    const wrappedCallback = (...args) => {
      try {
        const event = args[args.length - 1]; // Last arg is the event object
        callback(null, {
          eventName: sanitizedEventName,
          args: args.slice(0, -1),
          blockNumber: event.log?.blockNumber,
          transactionHash: event.log?.transactionHash,
        });
      } catch (error) {
        SecureLogger.error('Event callback error', { event: sanitizedEventName, error: error.message });
        callback(error, null);
      }
    };

    contract.on(sanitizedEventName, wrappedCallback);

    SecureLogger.info('Subscribed to event', { event: sanitizedEventName });

    // Return unsubscribe function
    return () => {
      contract.off(sanitizedEventName, wrappedCallback);
      SecureLogger.info('Unsubscribed from event', { event: sanitizedEventName });
    };
  }

  async queryPastEvents(contractKey, eventName, fromBlock = 0, toBlock = 'latest') {
    this._ensureConnected();

    const { contract } = this.getContract(contractKey);
    const sanitizedEventName = InputValidator.sanitizeString(eventName);

    try {
      const filter = contract.filters[sanitizedEventName]();
      const events = await contract.queryFilter(filter, fromBlock, toBlock);

      return events.map(event => ({
        eventName: sanitizedEventName,
        args: event.args,
        blockNumber: event.blockNumber,
        transactionHash: event.transactionHash,
      }));
    } catch (error) {
      throw new TransactionError(`Failed to query events: ${error.message}`);
    }
  }

  // ---- Utility Methods ----

  async getBalance(address) {
    this._ensureConnected();
    const validatedAddress = InputValidator.validateAddress(address);
    const balance = await this.provider.getBalance(validatedAddress);
    return {
      wei: balance.toString(),
      ether: ethers.formatEther(balance),
    };
  }

  async getCurrentGasPrice() {
    this._ensureConnected();
    const feeData = await this.provider.getFeeData();
    return {
      gasPrice: feeData.gasPrice?.toString(),
      maxFeePerGas: feeData.maxFeePerGas?.toString(),
      maxPriorityFeePerGas: feeData.maxPriorityFeePerGas?.toString(),
    };
  }

  async getSignerAddress() {
    this._ensureSigner();
    return await this.signer.getAddress();
  }

  getNetworkInfo() {
    return {
      chainId: this.currentNetwork,
      name: SUPPORTED_NETWORKS[this.currentNetwork]?.name || 'Unknown',
    };
  }

  // ---- ERC-20 Token Helpers ----

  async getERC20Info(tokenAddress) {
    const ERC20_ABI = [
      'function name() view returns (string)',
      'function symbol() view returns (string)',
      'function decimals() view returns (uint8)',
      'function totalSupply() view returns (uint256)',
      'function balanceOf(address) view returns (uint256)',
    ];

    const validatedAddress = InputValidator.validateAddress(tokenAddress);
    const key = this.loadContract(validatedAddress, ERC20_ABI, `erc20_${validatedAddress}`);

    try {
      const [name, symbol, decimals, totalSupply] = await Promise.all([
        this.readContract(key, 'name'),
        this.readContract(key, 'symbol'),
        this.readContract(key, 'decimals'),
        this.readContract(key, 'totalSupply'),
      ]);

      return { address: validatedAddress, name, symbol, decimals, totalSupply };
    } catch (error) {
      throw new TransactionError(`Failed to get ERC-20 info: ${error.message}`);
    }
  }

  async getERC20Balance(tokenAddress, walletAddress) {
    const ERC20_ABI = [
      'function balanceOf(address) view returns (uint256)',
      'function decimals() view returns (uint8)',
    ];

    const validatedTokenAddress = InputValidator.validateAddress(tokenAddress);
    const validatedWalletAddress = InputValidator.validateAddress(walletAddress);
    const key = this.loadContract(validatedTokenAddress, ERC20_ABI, `erc20bal_${validatedTokenAddress}`);

    const [balance, decimals] = await Promise.all([
      this.readContract(key, 'balanceOf', [validatedWalletAddress]),
      this.readContract(key, 'decimals'),
    ]);

    return {
      raw: balance.toString(),
      formatted: ethers.formatUnits(balance, decimals),
      decimals,
    };
  }

  // ---- Private Helper Methods ----

  _ensureConnected() {
    if (!this.connected || !this.provider) {
      throw new ConnectionError('Not connected. Call connectWithBrowserWallet() or connectWithProvider() first.');
    }
  }

  _ensureSigner() {
    if (!this.signer) {
      throw new ConnectionError('No signer available. Connect with a wallet to send transactions.');
    }
  }

  _formatResult(result, fragment) {
    if (fragment.outputs.length === 1) {
      return result;
    }
    // For multiple return values, return as named object
    const formatted = {};
    fragment.outputs.forEach((output, index) => {
      const key = output.name || `value${index}`;
      formatted[key] = result[index];
    });
    return formatted;
  }

  _decodeRevertReason(error) {
    if (error.reason) return error.reason;
    if (error.data) {
      try {
        const iface = new ethers.Interface(['function Error(string)']);
        const decoded = iface.decodeFunctionData('Error', error.data);
        return decoded[0];
      } catch {
        return error.message || 'Unknown revert reason';
      }
    }
    return error.message || 'Unknown error';
  }

  disconnect() {
    this.provider = null;
    this.signer = null;
    this.contracts.clear();
    this.connected = false;
    this.currentNetwork = null;
    this.nonceManager = new NonceManager();
    SecureLogger.info('Disconnected');
  }
}

// ============================================
// Transaction Receipt Monitor
// ============================================

class TransactionMonitor {
  constructor(provider) {
    this.provider = provider;
    this.pendingTxs = new Map();
  }

  async trackTransaction(txHash, callbacks = {}) {
    const { onConfirmed, onFailed, onSpeedUp } = callbacks;

    this.pendingTxs.set(txHash, { status: 'pending', timestamp: Date.now() });

    try {
      const receipt = await this.provider.waitForTransaction(txHash, 1, TX_TIMEOUT_MS);

      if (receipt.status === 1) {
        this.pendingTxs.set(txHash, { status: 'confirmed', receipt });
        if (onConfirmed) onConfirmed(receipt);
      } else {
        this.pendingTxs.set(txHash, { status: 'failed', receipt });
        if (onFailed) onFailed(receipt);
      }

      return receipt;
    } catch (error) {
      this.pendingTxs.set(txHash, { status: 'error', error: error.message });
      if (onFailed) onFailed(error);
      throw error;
    }
  }

  getPendingTransactions() {
    const pending = [];
    for (const [hash, info] of this.pendingTxs) {
      if (info.status === 'pending') {
        pending.push({ hash, ...info });
      }
    }
    return pending;
  }
}

