// Usage Example / Demo
// ============================================

async function exampleUsage() {
  // Initialize the DApp interactor
  const dapp = new DAppContractInteractor({
    maxRequestsPerMinute: 20,
    infuraApiKey: 'YOUR_INFURA_KEY',
  });

  try {
    // Connect with browser wallet (MetaMask)
    const connection = await dapp.connectWithBrowserWallet();
    console.log(`Connected: ${connection.address} on network ${connection.network}`);

    // Example: Load a contract (e.g., a simple ERC-20 token)
    const tokenABI = [
      'function name() view returns (string)',
      'function symbol() view returns (string)',
      'function decimals() view returns (uint8)',
      'function totalSupply() view returns (uint256)',
      'function balanceOf(address owner) view returns (uint256)',
      'function transfer(address to, uint256 amount) returns (bool)',
      'function approve(address spender, uint256 amount) returns (bool)',
      'function allowance(address owner, address spender) view returns (uint256)',
      'event Transfer(address indexed from, address indexed to, uint256 value)',
      'event Approval(address indexed owner, address indexed spender, uint256 value)',
    ];

    const contractAddress = '0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48'; // USDC on mainnet
    const contractKey = dapp.loadContract(contractAddress, tokenABI, 'USDC');

    // Read contract data
    const name = await dapp.readContract(contractKey, 'name');
    const symbol = await dapp.readContract(contractKey, 'symbol');
    console.log(`Token: ${name} (${symbol})`);

    // Check balance
    const signerAddress = await dapp.getSignerAddress();
    const balance = await dapp.readContract(contractKey, 'balanceOf', [signerAddress]);
    console.log(`Balance: ${balance}`);

    // Send a transaction (transfer tokens)
    const recipientAddress = '0x742d35Cc6634C0532925a3b844Bc9e7595f2bD18';
    const amount = ethers.parseUnits('10', 6); // 10 USDC (6 decimals)

    const txResult = await dapp.sendTransaction(contractKey, 'transfer', [recipientAddress, amount]);
    console.log(`Transaction sent: ${txResult.hash}`);

    // Wait for confirmation
    const receipt = await txResult.wait();
    console.log(`Confirmed in block ${receipt.blockNumber}, gas used: ${receipt.gasUsed}`);

    // Subscribe to Transfer events
    const unsubscribe = dapp.subscribeToEvents(contractKey, 'Transfer', (error, event) => {
      if (error) {
        console.error('Event error:', error);
        return;
      }
      console.log(`Transfer: ${event.args[0]} -> ${event.args[1]}: ${event.args[2]}`);
    });

    // Get ETH balance
    const ethBalance = await dapp.getBalance(signerAddress);
    console.log(`ETH Balance: ${ethBalance.ether} ETH`);

    // Get gas price
    const gasInfo = await dapp.getCurrentGasPrice();
    console.log(`Gas Price: ${gasInfo.gasPrice}`);

    // Batch read
    const batchResults = await dapp.batchRead(contractKey, [
      { functionName: 'name' },
      { functionName: 'symbol' },
      { functionName: 'decimals' },
      { functionName: 'totalSupply' },
    ]);
    console.log('Batch results:', batchResults);

    // Cleanup
    unsubscribe();

  } catch (error) {
    if (error instanceof ValidationError) {
      console.error('Validation Error:', error.message);
    } else if (error instanceof TransactionError) {
      console.error('Transaction Error:', error.message, error.txHash);
    } else if (error instanceof ConnectionError) {
      console.error('Connection Error:', error.message);
    } else {
      console.error('Unexpected Error:', error.message);
    }
  } finally {
    // dapp.disconnect();
  }
}

